import collections

class Solution:
    def orangesRotting(self, grid: list[list[int]]) -> int:
        rows, cols = len(grid), len(grid[0])
        q = collections.deque()
        fresh_count = 0

        # İlk turda çürük portakalları kuyruğa ekle ve taze portakalları say
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 2:
                    q.append((r, c))
                elif grid[r][c] == 1:
                    fresh_count += 1

        # Hiç taze portakal yoksa, zaman 0'dır.
        if fresh_count == 0:
            return 0

        time = 0
        directions = [(0, 1), (0, -1), (1, 0), (-1, 0)] # Sağ, Sol, Aşağı, Yukarı

        # BFS döngüsü
        while q and fresh_count > 0:
            time += 1 # Bir dakika geçer
            current_level_size = len(q)

            for _ in range(current_level_size):
                r, c = q.popleft()

                for dr, dc in directions:
                    nr, nc = r + dr, c + dc

                    # Sınır kontrolü ve taze portakal mı?
                    if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == 1:
                        grid[nr][nc] = 2 # Portakalı çürük olarak işaretle
                        fresh_count -= 1
                        q.append((nr, nc))

        # Tüm taze portakallar çürüdü mü kontrol et
        if fresh_count == 0:
            return time
        else:
            return -1 # Bazı taze portakallar çürütülemedi
